def minPath(grid, k):
    n = len(grid)
    start_r, start_c = -1, -1
    for r in range(n):
        for c in range(n):
            if grid[r][c] == 1:
                start_r, start_c = r, c
                break
        if start_r != -1:
            break

    path = [1]
    curr_r, curr_c = start_r, start_c

    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for _ in range(k - 1):
        min_val = float('inf')
        next_r, next_c = -1, -1
        for dr, dc in directions:
            nr, nc = curr_r + dr, curr_c + dc
            if 0 <= nr < n and 0 <= nc < n:
                val = grid[nr][nc]
                if val < min_val:
                    min_val = val
                    next_r, next_c = nr, nc
        path.append(min_val)
        curr_r, curr_c = next_r, next_c

    return path

