def find_longest_repeating_subseq(s):
    n = len(s)
    # dp[i][j] stores the length of the longest repeating subsequence
    # considering the first i characters and first j characters of s
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, n + 1):
            # Characters match and they must come from different indices in the original string
            if s[i-1] == s[j-1] and i != j:
                dp[i][j] = 1 + dp[i-1][j-1]
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])

    return dp[n][n]

