def set_left_most_unset_bit(n):
    if n == 0:
        return 0
    mask = (1 << n.bit_length()) - 1
    unset_bits = (~n) & mask
    if unset_bits == 0:
        return n
    return n | (1 << (unset_bits.bit_length() - 1))

