def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0 # Though usually n >= 1
    if n == 1:
        return 1 if m == 0 else 0

    # Memoization
    memo = {}

    def helper(n, m):
        if m < 0 or m >= n:
            return 0
        if n == 1:
            return 1 if m == 0 else 0

        state = (n, m)
        if state in memo:
            return memo[state]

        # Recurrence: A(n, m) = (m+1)A(n-1, m) + (n-m)A(n-1, m-1)
        val = (m + 1) * helper(n - 1, m) + (n - m) * helper(n - 1, m - 1)
        memo[state] = val
        return val

    return helper(n, m)

