import heapq

def find_minimum_range(nums):
    if not nums:
        return (0, 0)

    # Sort each array to ensure we can process in order
    for arr in nums:
        arr.sort()

    heap = []
    current_max = float('-inf')

    for i, arr in enumerate(nums):
        if arr:
            heapq.heappush(heap, (arr[0], i, 0))
            current_max = max(current_max, arr[0])

    min_range = (heap[0][0], current_max)

    while True:
        val, arr_idx, elem_idx = heapq.heappop(heap)

        if elem_idx + 1 >= len(nums[arr_idx]):
            break

        next_val = nums[arr_idx][elem_idx + 1]
        heapq.heappush(heap, (next_val, arr_idx, elem_idx + 1))
        current_max = max(current_max, next_val)

        current_min = heap[0][0]
        current_len = current_max - current_min
        min_len = min_range[1] - min_range[0]

        if current_len < min_len or (current_len == min_len and current_min < min_range[0]):
            min_range = (current_min, current_max)

    return min_range

