def find_peak(arr, n):
    low = 0
    high = n - 1

    while low <= high:
        mid = (low + high) // 2

        # Check if mid is a peak
        if (mid == 0 or arr[mid - 1] < arr[mid]) and (mid == n - 1 or arr[mid + 1] < arr[mid]):
            return mid

        # If left neighbor is greater, peak must be on the left
        elif mid > 0 and arr[mid - 1] > arr[mid]:
            high = mid - 1

        # Otherwise, peak must be on the right
        else:
            low = mid + 1

    return -1

def binomial_Coeff(n, k):
    if k < 0 or k > n:
        return 0
    k = min(k, n - k)
    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

