            if dp[j - num]:
                dp[j] = True
    return dp[target_sum]

def max_sum_increasing_subseq(arr, n, i, k):
    dp = [0] * (i + 1)
    max_sum = 0

    for j in range(i + 1):
        if arr[j] >= arr[k]:
            continue

        dp[j] = arr[j]
        for p in range(j):
            if arr[p] < arr[j]:
                if dp[p] + arr[j] > dp[j]:
                    dp[j] = dp[p] + arr[j]

        if dp[j] > max_sum:
            max_sum = dp[j]

    return max_sum + arr[k]

