def magic_square_test(matrix):
    # Check if matrix is empty
    if not matrix:
        return False

    n = len(matrix)

    # Check if it is a square matrix
    for row in matrix:
        if len(row) != n:
            return False

    # Check if the matrix contains all numbers from 1 to n^2 exactly once
    # Flatten the matrix to check elements
    elements = set()
    for row in matrix:
        for x in row:
            elements.add(x)

    expected_elements = set(range(1, n * n + 1))
    if elements != expected_elements:
        return False

    # Calculate the magic constant (sum of the first row)
    magic_sum = sum(matrix[0])

    # Check row sums
    for row in matrix:
        if sum(row) != magic_sum:
            return False

    # Check column sums
    for j in range(n):
        col_sum = sum(matrix[i][j] for i in range(n))
        if col_sum != magic_sum:
            return False

    # Check main diagonal sum
    diag1_sum = sum(matrix[i][i] for i in range(n))
    if diag1_sum != magic_sum:
        return False

    # Check anti-diagonal sum
    diag2_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if diag2_sum != magic_sum:
        return False

    return True

