def max_sum_rectangular_grid(grid, n):
    col_max = [max(grid[0][i], grid[1][i]) for i in range(n)]
    if n == 0:
        return 0
    if n == 1:
        return col_max[0]
    prev2 = col_max[0]
    prev1 = max(col_max[0], col_max[1])
    for i in range(2, n):
        curr = max(prev1, prev2 + col_max[i])
        prev2, prev1 = prev1, curr
    return prev1

