from collections import Counter

def rearange_string(s: str) -> str:
    if not s:
        return ""
    freq = Counter(s)
    n = len(s)
    if max(freq.values()) > (n + 1) // 2:
        return ""

    sorted_chars = sorted(freq.items(), key=lambda x: (-x[1], x[0]))
    res = [''] * n
    idx = 0

    for char, count in sorted_chars:
        for _ in range(count):
            if idx >= n:
                idx = 1
            res[idx] = char
            idx += 2

    return "".join(res)

def is_woodall(n):
