def split_lowerstring(s):
    res = []
    current = []
    for char in s:
        if char.islower():
            if current:
                res.append(''.join(current))
            current = [char]
        else:
            current.append(char)
    if current:
        res.append(''.join(current))
    if res and res[0][0].isupper():
        res = res[1:]
    return res

