def get_maxgold(gold, m, n):
    # Initialize DP table with zeros
    dp = [[0] * n for _ in range(m)]

    # Base case: first column values are the starting gold amounts
    for i in range(m):
        dp[i][0] = gold[i][0]

    # Fill DP table column by column
    for j in range(1, n):
        for i in range(m):
            # Maximum gold from the three possible previous moves
            right = dp[i][j-1]
            right_up = dp[i-1][j-1] if i > 0 else 0
            right_down = dp[i+1][j-1] if i < m - 1 else 0

            dp[i][j] = gold[i][j] + max(right, right_up, right_down)

    # The answer is the maximum value in the last column
